// LocalDataManager.js

import AsyncStorage from '@react-native-async-storage/async-storage';

const STORAGE_KEYS = {
  USER_TOKEN: '@user_token',
  USER_PROFILE: '@user_profile',
  APP_SETTINGS: '@app_settings',
  OFFLINE_CONTENT_PREFIX: '@offline_content:', // + contentId
};

const LocalDataManager = {
  // Utility
  async _save(key, value) {
    const data = typeof value === 'string' ? value : JSON.stringify(value);
    await AsyncStorage.setItem(key, data);
  },

  async _load(key, isJson = true) {
    const data = await AsyncStorage.getItem(key);
    if (data == null) return null;
    return isJson ? JSON.parse(data) : data;
  },

  async _remove(key) {
    await AsyncStorage.removeItem(key);
  },

  // User Token
  async setUserToken(token) {
    await this._save(STORAGE_KEYS.USER_TOKEN, token);
  },

  async getUserToken() {
    return this._load(STORAGE_KEYS.USER_TOKEN, false);
  },

  async clearUserToken() {
    await this._remove(STORAGE_KEYS.USER_TOKEN);
  },

  // User Profile
  async setUserProfile(profile) {
    await this._save(STORAGE_KEYS.USER_PROFILE, profile);
  },

  async getUserProfile() {
    return this._load(STORAGE_KEYS.USER_PROFILE);
  },

  async clearUserProfile() {
    await this._remove(STORAGE_KEYS.USER_PROFILE);
  },

  // App Settings
  async setAppSettings(settings) {
    await this._save(STORAGE_KEYS.APP_SETTINGS, settings);
  },

  async getAppSettings() {
    return this._load(STORAGE_KEYS.APP_SETTINGS);
  },

  async updateAppSettings(partialSettings) {
    const current = (await this.getAppSettings()) || {};
    await this.setAppSettings({ ...current, ...partialSettings });
  },

  async clearAppSettings() {
    await this._remove(STORAGE_KEYS.APP_SETTINGS);
  },

  // Offline Content
  _offlineKey(id) {
    return `${STORAGE_KEYS.OFFLINE_CONTENT_PREFIX}${id}`;
  },

  async setOfflineContent(id, content) {
    await this._save(this._offlineKey(id), content);
  },

  async getOfflineContent(id) {
    return this._load(this._offlineKey(id));
  },

  async removeOfflineContent(id) {
    await this._remove(this._offlineKey(id));
  },

  async getAllOfflineContent() {
    const keys = await AsyncStorage.getAllKeys();
    const contentKeys = keys.filter(k => k.startsWith(STORAGE_KEYS.OFFLINE_CONTENT_PREFIX));
    const pairs = await AsyncStorage.multiGet(contentKeys);
    return pairs.reduce((acc, [key, val]) => {
      const id = key.replace(STORAGE_KEYS.OFFLINE_CONTENT_PREFIX, '');
      acc[id] = val ? JSON.parse(val) : null;
      return acc;
    }, {});
  },

  // Clear everything
  async clearAll() {
    const keys = await AsyncStorage.getAllKeys();
    const managedKeys = keys.filter(
      k =>
        k === STORAGE_KEYS.USER_TOKEN ||
        k === STORAGE_KEYS.USER_PROFILE ||
        k === STORAGE_KEYS.APP_SETTINGS ||
        k.startsWith(STORAGE_KEYS.OFFLINE_CONTENT_PREFIX)
    );
    await AsyncStorage.multiRemove(managedKeys);
  },
};

export default LocalDataManager;